App.views.pedidos=function(){document.getElementById('bottom-nav').style.display='flex';const pN=[];const pT=[];const pL=[];const pP=[];[...(App.state.pedidos||[])].reverse().slice(0,100).forEach(p=>{const d=App.state.pedido_detalle.find(x=>x.pedido_id===p.id);const to=d?App.state.ordenes_produccion.some(o=>o.pedido_detalle_id===d.id):false;const ab=App.state.abonos.filter(a=>a.pedido_id===p.id).reduce((s,a)=>s+parseFloat(a.monto||0),0);const sr=parseFloat(p.total||0)-parseFloat(p.anticipo||0)-ab;let ec=p.estado||'nuevo';if(to&&ec!=='listo para entregar'&&ec!=='pagado')ec='en taller';if(sr<=0)ec='pagado';p._o=d;p._t=to;p._s=sr;p._ec=ec;if(ec==='pagado')pP.push(p);else if(ec==='listo para entregar')pL.push(p);else if(ec==='en taller')pT.push(p);else pN.push(p);});const dt=(p)=>{const c=App.state.clientes.find(x=>x.id===p.cliente_id);const nc=p.cliente_id==="STOCK_INTERNO"?"📦 BODEGA":(c?c.nombre:'Mostrador');const prod=p._o?App.state.productos.find(x=>x.id===p._o.producto_id):null;const ep=p._s<=0;let eu=false;if(p.fecha_entrega&&!ep&&p._ec!=='listo para entregar'){const fe=new Date(p.fecha_entrega+'T00:00:00');const hy=new Date();hoy.setHours(0,0,0,0);if(Math.ceil((fe-hy)/86400000)<=7)eu=true;}let ba='';if(!p._t&&p._ec==='nuevo'){if(prod&&prod.categoria==='reventa'){ba=`<button class="btn btn-secondary" style="padding:6px 10px;border-color:#3182CE;color:#3182CE;" onclick="App.logic.entregarDeBodega('${p.id}')">📦 Sacar de Bodega</button>`;}else{ba=`<button class="btn btn-secondary" style="padding:6px 10px;border-color:var(--secondary);color:var(--secondary);" onclick="App.views.formMandarProduccion('${p.id}')">🔨 Mandar a taller</button><button class="btn btn-secondary" style="padding:6px 10px;border-color:#3182CE;color:#3182CE;margin-left:5px;" onclick="App.logic.entregarDeBodega('${p.id}')">📦 Bodega</button>`;}}return `<div class="card tarj-ped" data-estado="${p._ec}" style="border:${eu?'2px solid var(--danger)':'1px solid var(--border)'};box-shadow:none;"><div style="display:flex;justify-content:space-between;margin-bottom:8px;"><strong>${(p.id||'').replace('PED-','')} - ${nc}</strong>${ep?`<span class="badge" style="background:var(--success);color:white;">PAGADO</span>`:`<span class="badge ${p._ec||'nuevo'}">${String(p._ec||'Nuevo').toUpperCase()}</span>`}</div><p style="color:var(--primary);font-size:0.9rem;font-weight:bold;margin-bottom:5px;">${prod?prod.nombre:'Desconocido'}</p><div style="display:flex;justify-content:space-between;align-items:center;margin-top:10px;padding-top:10px;border-top:1px dashed var(--border);"><div><strong style="color:${ep?'var(--success)':'var(--danger)'};">Saldo: $${p._s>0?p._s:0}</strong></div><div style="display:flex;gap:8px;">${ba}${!ep&&p.cliente_id!=="STOCK_INTERNO"?`<button class="btn btn-primary" style="padding:6px 10px;background:var(--success);border-color:var(--success);" onclick="App.views.formCobrar('${p.id}','${c?c.id:''}',${p._s})">💰</button>`:''}</div></div><div style="display:flex;gap:10px;margin-top:15px;">${p.cliente_id!=="STOCK_INTERNO"?`<button class="btn btn-secondary" style="flex:1;font-size:0.8rem;border-color:#38A169;color:#38A169;" onclick="App.views.modalOpcionesWhatsApp('${p.id}')">💬 WApp</button><button class="btn btn-secondary" style="flex:1;font-size:0.8rem;border-color:var(--primary);color:var(--primary);" onclick="App.logic.imprimirNota('${p.id}')">🖨️ PDF</button>`:''}<button class="btn btn-secondary" style="font-size:0.8rem;padding:6px 10px;" onclick="App.views.formEditarPedido('${p.id}')">✏️</button><button class="btn btn-secondary" style="font-size:0.8rem;padding:6px 10px;color:red;border-color:red;" onclick="App.logic.eliminarPedido('${p.id}')">🗑️</button></div></div>`;};return `<div class="card"><h3 class="card-title">Gestión de Pedidos</h3><input type="text" id="bus-ped" onkeyup="window.filtrarLista('bus-ped','tarj-ped')" placeholder="🔍 Buscar..." style="width:100%;padding:8px;margin-bottom:15px;border-radius:6px;border:1px solid var(--border);"><div style="display:flex;margin-bottom:15px;background:white;border-radius:8px;overflow-x:auto;border:1px solid var(--border);"><button class="tab-btn-ped" style="flex:1;min-width:80px;padding:12px 5px;border:none;background:#F3F0FF;color:var(--primary);font-weight:bold;font-size:0.85rem;border-bottom:2px solid var(--primary);" onclick="window.switchTabPed('nuevos',this)">Nuevos (${pN.length})</button><button class="tab-btn-ped" style="flex:1;min-width:80px;padding:12px 5px;border:none;background:transparent;color:var(--text-muted);font-weight:bold;font-size:0.85rem;border-bottom:2px solid transparent;" onclick="window.switchTabPed('taller',this)">Taller (${pT.length})</button><button class="tab-btn-ped" style="flex:1;min-width:80px;padding:12px 5px;border:none;background:transparent;color:var(--text-muted);font-weight:bold;font-size:0.85rem;border-bottom:2px solid transparent;" onclick="window.switchTabPed('listos',this)">Listos (${pL.length})</button><button class="tab-btn-ped" style="flex:1;min-width:80px;padding:12px 5px;border:none;background:transparent;color:var(--text-muted);font-weight:bold;font-size:0.85rem;border-bottom:2px solid transparent;" onclick="window.switchTabPed('pagados',this)">Pagados</button></div><div id="tab-nuevos" class="tab-content-ped" style="display:block;">${pN.length===0?'<div class="card" style="text-align:center;color:var(--text-muted);padding:30px;">Vacio</div>':pN.map(dt).join('')}</div><div id="tab-taller" class="tab-content-ped" style="display:none;">${pT.length===0?'<div class="card" style="text-align:center;color:var(--text-muted);padding:30px;">Vacio</div>':pT.map(dt).join('')}</div><div id="tab-listos" class="tab-content-ped" style="display:none;">${pL.length===0?'<div class="card" style="text-align:center;color:var(--text-muted);padding:30px;">Vacio</div>':pL.map(dt).join('')}</div><div id="tab-pagados" class="tab-content-ped" style="display:none;">${pP.length===0?'<div class="card" style="text-align:center;color:var(--text-muted);padding:30px;">Vacio</div>':pP.map(dt).join('')}</div></div><button class="fab" onclick="App.views.formNuevoPedido()">+</button>`;};
App.views.produccion=function(){document.getElementById('bottom-nav').style.display='flex';const p=(App.state.ordenes_produccion||[]).filter(o=>o.estado==='pendiente'||!o.estado);const ep=(App.state.ordenes_produccion||[]).filter(o=>o.estado==='en_proceso');const l=(App.state.ordenes_produccion||[]).filter(o=>o.estado==='listo');const dt=(o)=>{const det=App.state.pedido_detalle.find(d=>d.id===o.pedido_detalle_id)||App.state.pedido_detalle.find(d=>d.pedido_id===o.pedido_detalle_id)||{};const prod=det.producto_id?App.state.productos.find(x=>x.id===det.producto_id):null;const ped=App.state.pedidos.find(x=>x.id===det.pedido_id)||{};let nc='Sin Cliente';if(ped.cliente_id==="STOCK_INTERNO")nc="📦 BODEGA";else if(ped.cliente_id){const c=App.state.clientes.find(x=>x.id===ped.cliente_id);if(c)nc=c.nombre;}const pa=App.state.pago_artesanos.filter(x=>x.orden_id===o.id);let ia=pa.length>0?`🛠️ ${pa.length} Trabajos`:'👤 Sin asignar';let sf='';if(ped.fecha_entrega&&o.estado!=='listo'){const fe=new Date(ped.fecha_entrega+'T00:00:00');const hy=new Date();hy.setHours(0,0,0,0);const df=Math.ceil((fe-hy)/86400000);if(df<0)sf='<span style="background:red;color:white;padding:2px 6px;border-radius:4px;font-size:0.7rem;margin-left:5px;">🔴 Atrasado</span>';else if(df<=1)sf='<span style="background:orange;color:white;padding:2px 6px;border-radius:4px;font-size:0.7rem;margin-left:5px;">🟡 Urgente</span>';else sf='<span style="background:green;color:white;padding:2px 6px;border-radius:4px;font-size:0.7rem;margin-left:5px;">🟢 A tiempo</span>';}return `<div class="card" style="border:1px solid var(--border);box-shadow:none;cursor:pointer;margin-bottom:10px;" onclick="App.views.modalEditarOrden('${o.id}')"><div style="display:flex;justify-content:space-between;margin-bottom:5px;"><strong>${o.id}</strong><div><span style="font-size:0.75rem;color:#718096;font-weight:bold;">${ped.id?(ped.id||'').replace('PED-',''):'Huérfana'}</span>${sf}</div></div><small style="color:var(--primary);font-weight:600;display:block;font-size:1rem;margin-bottom:2px;">${prod?prod.nombre:'Producto interno'}</small><small style="color:#4A5568;display:block;margin-bottom:5px;font-weight:bold;">👤 ${nc}</small><div style="margin-top:8px;font-size:0.85rem;color:var(--text-muted);display:flex;justify-content:space-between;border-top:1px dashed #E2E8F0;padding-top:8px;"><span>${ia}</span><span style="color:var(--primary);">Ver detalles ➔</span></div></div>`;};return `<div class="card"><h3 class="card-title">Taller</h3><button class="btn btn-secondary" style="width:100%;margin-top:5px;border:2px dashed var(--primary);color:var(--primary);background:transparent;font-weight:bold;" onclick="App.views.formOrdenStock()">+ 🔨 Fabricar para Bodega</button></div><div style="display:flex;margin-bottom:15px;background:white;border-radius:8px;overflow:hidden;border:1px solid var(--border);"><button class="tab-btn-prod" style="flex:1;padding:12px 5px;border:none;background:#F3F0FF;color:var(--primary);font-weight:bold;font-size:0.85rem;border-bottom:2px solid var(--primary);" onclick="window.switchTabProd('pendientes',this)">🕒 Pendientes (${p.length})</button><button class="tab-btn-prod" style="flex:1;padding:12px 5px;border:none;background:transparent;color:var(--text-muted);font-weight:bold;font-size:0.85rem;border-bottom:2px solid transparent;" onclick="window.switchTabProd('en_proceso',this)">🏃 En Proceso (${ep.length})</button><button class="tab-btn-prod" style="flex:1;padding:12px 5px;border:none;background:transparent;color:var(--text-muted);font-weight:bold;font-size:0.85rem;border-bottom:2px solid transparent;" onclick="window.switchTabProd('listas',this)">✅ Listas (${l.length})</button></div><div id="tab-pendientes" class="tab-content-prod" style="display:block;">${p.length===0?'<div class="card" style="text-align:center;color:var(--text-muted);padding:30px;">Vacio</div>':p.map(dt).join('')}</div><div id="tab-en_proceso" class="tab-content-prod" style="display:none;">${ep.length===0?'<div class="card" style="text-align:center;color:var(--text-muted);padding:30px;">Vacio</div>':ep.map(dt).join('')}</div><div id="tab-listas" class="tab-content-prod" style="display:none;">${l.length===0?'<div class="card" style="text-align:center;color:var(--text-muted);padding:30px;">Vacio</div>':l.map(dt).join('')}</div>`;};
App.views.nomina=function(){document.getElementById('bottom-nav').style.display='flex';let html=`<div class="card"><h3 class="card-title">Nómina</h3>`;const ppa={};App.state.artesanos.forEach(a=>{ppa[a.id]={n:a.nombre,tp:0,t:[]};});App.state.pago_artesanos.forEach(p=>{if(p.estado==='pendiente'&&ppa[p.artesano_id]){ppa[p.artesano_id].tp+=parseFloat(p.total);ppa[p.artesano_id].t.push(p);}});let h=false;for(const[id,d]of Object.entries(ppa)){if(d.tp>0){h=true;html+=`<div class="card" style="border:1px solid var(--border);box-shadow:none;"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;"><strong>🧑‍🎨 ${d.n}</strong><strong style="color:var(--danger);font-size:1.1rem;">$${d.tp}</strong></div><div style="display:flex;gap:10px;"><button class="btn btn-secondary" style="flex:1;border-color:var(--primary);color:var(--primary);background:transparent;" onclick="App.views.detalleNominaArtesano('${id}')">📋 Detalles</button><button class="btn btn-primary" style="flex:1;background:var(--success);border-color:var(--success);" onclick="if(confirm('¿Liquidar $${d.tp} a ${d.n}?')) App.logic.liquidarNomina('${id}')">💵 Liquidar</button></div></div>`;}}if(!h)html+=`<p style="color:var(--text-muted);">Todo al día. ✨</p>`;html+=`</div>`;return html;};
App.views.detalleNominaArtesano=function(aId){const a=App.state.artesanos.find(x=>x.id===aId);const pp=App.state.pago_artesanos.filter(x=>x.artesano_id===aId&&x.estado==='pendiente');let html=`<div style="margin-bottom:15px;"><p style="color:var(--text-muted);font-size:0.85rem;">Trabajos de <strong>${a.nombre}</strong>:</p><ul style="list-style:none;padding:0;margin:0;">`;pp.forEach(p=>{const o=App.state.ordenes_produccion.find(x=>x.id===p.orden_id);let np='Orden '+(p.orden_id||'').replace('ORD-','');if(o){const d=App.state.pedido_detalle.find(x=>x.id===o.pedido_detalle_id);if(d){const pr=App.state.productos.find(x=>x.id===d.producto_id);if(pr)np=pr.nombre;}}const nt=(p.id.split('-').length>2)?p.id.split('-').slice(2).join(' '):'Trabajo';html+=`<li style="padding:10px 0;border-bottom:1px dashed #ccc;display:flex;justify-content:space-between;align-items:center;"><div><strong>${nt}</strong><br><small style="color:var(--text-muted);">${np}</small><br><small style="color:var(--text-muted);">${p.fecha.split('T')[0]}</small></div><div style="text-align:right;"><span style="color:var(--danger);font-weight:bold;display:block;margin-bottom:5px;">$${p.total}</span><button class="btn btn-secondary" style="padding:2px 6px;font-size:0.7rem;color:red;border-color:red;" onclick="App.ui.closeSheet(); App.logic.eliminarRegistroGenerico('pago_artesanos','${p.id}','pago_artesanos')">🗑️</button></div></li>`;});html+=`</ul><button class="btn btn-primary" style="width:100%;margin-top:15px;" onclick="App.ui.closeSheet()">Cerrar</button></div>`;App.ui.openSheet(`Nómina`,html);};
App.views.modalEstadoCuenta=function(cId){const c=App.state.clientes.find(x=>x.id===cId);if(!c)return;const pc=App.state.pedidos.filter(x=>x.cliente_id===cId);let tc=0;let sp=0;let lp='';pc.forEach(p=>{tc+=parseFloat(p.total||0);const ab=App.state.abonos.filter(a=>a.pedido_id===p.id).reduce((s,a)=>s+parseFloat(a.monto||0),0);const d=parseFloat(p.total||0)-parseFloat(p.anticipo||0)-ab;if(d>0)sp+=d;const det=App.state.pedido_detalle.find(x=>x.pedido_id===p.id);const prod=det?App.state.productos.find(x=>x.id===det.producto_id):null;const np=prod?prod.nombre:'Artículo';lp+=`<li style="padding:8px 0;border-bottom:1px dashed #ccc;display:flex;justify-content:space-between;"><span><strong>${(p.id||'').replace('PED-','')}</strong> - <small style="color:var(--primary);font-weight:bold;">${np}</small><br><small>${p.fecha_creacion.split('T')[0]}</small></span><span style="color:var(--primary);font-weight:bold;">$${p.total}</span></li>`;});if(lp==='')lp='<li style="padding:10px;color:var(--text-muted);">Sin pedidos.</li>';let html=`<div class="grid-2" style="margin-bottom:15px;"><div class="card stat-card" style="background:#EBF8FF;"><div class="label" style="color:#2B6CB0;">Total Comprado</div><div class="value" style="color:#3182CE;font-size:1.2rem;">$${tc.toFixed(2)}</div></div><div class="card stat-card" style="background:#FFF5F5;"><div class="label" style="color:#C53030;">Saldo Pendiente</div><div class="value" style="color:#E53E3E;font-size:1.2rem;">$${sp.toFixed(2)}</div></div></div><h4 style="margin-bottom:10px;color:var(--text-main);">Historial</h4><ul style="list-style:none;padding:0;margin:0;max-height:250px;overflow-y:auto;background:#f9f9f9;border-radius:8px;padding:10px;border:1px solid var(--border);">${lp}</ul><button class="btn btn-primary" style="width:100%;margin-top:15px;" onclick="App.ui.closeSheet()">Cerrar</button>`;App.ui.openSheet(`👤 ${c.nombre}`,html);};
App.views.modalOpcionesWhatsApp=function(pId){App.ui.openSheet("Enviar WhatsApp",`<div style="display:flex;flex-direction:column;gap:10px;"><p style="font-size:0.85rem;color:var(--text-muted);">Elige el mensaje:</p><button class="btn btn-secondary" style="border-color:#38A169;color:#38A169;background:transparent;" onclick="App.logic.enviarWhatsApp('${pId}','listo')">✅ Aviso "Pedido Listo"</button><button class="btn btn-secondary" style="border-color:#D69E2E;color:#D69E2E;background:transparent;" onclick="App.logic.enviarWhatsApp('${pId}','cobro')">💰 Recordatorio Pago</button><button class="btn btn-secondary" style="border-color:var(--primary);color:var(--primary);background:transparent;" onclick="App.logic.enviarWhatsApp('${pId}','general')">📝 Detalles General</button></div>`);};
App.views.modalEditarOrden=function(oId){const o=App.state.ordenes_produccion.find(x=>x.id===oId);if(!o)return App.ui.toast("No encontrada.");const d=App.state.pedido_detalle.find(x=>x.id===o.pedido_detalle_id)||App.state.pedido_detalle.find(x=>x.pedido_id===o.pedido_detalle_id)||{};const p=App.state.pedidos.find(x=>x.id===d.pedido_id)||{total:0};const pa=App.state.pago_artesanos.filter(x=>x.orden_id===oId);const cmo=pa.reduce((s,x)=>s+parseFloat(x.total),0);let cm=0;try{if(o.receta_personalizada){JSON.parse(o.receta_personalizada).forEach(i=>{const m=App.state.inventario.find(x=>x.id===i.mat_id);if(m)cm+=(parseFloat(i.cant)*parseFloat(m.costo_unitario||0));});}}catch(e){}const tv=parseFloat(p.total);const un=tv-cm-cmo;let cu=un>0?'var(--success)':'var(--danger)';let ph=`<div style="background:#F0FFF4;padding:10px;border-radius:6px;margin-bottom:15px;border:1px solid #C6F6D5;"><h4 style="margin-bottom:5px;color:#276749;">📊 Rentabilidad</h4><div style="display:flex;justify-content:space-between;font-size:0.85rem;"><span>Venta:</span><strong>$${tv.toFixed(2)}</strong></div><div style="display:flex;justify-content:space-between;font-size:0.85rem;"><span style="color:var(--danger);">- Hilos:</span><strong>$${cm.toFixed(2)}</strong></div><div style="display:flex;justify-content:space-between;font-size:0.85rem;"><span style="color:var(--danger);">- Mano Obra:</span><strong>$${cmo.toFixed(2)}</strong></div><hr style="margin:5px 0;border-top:1px dashed #C6F6D5;"><div style="display:flex;justify-content:space-between;font-size:1.1rem;color:${cu};"><span>Limpia:</span><strong>$${un.toFixed(2)}</strong></div></div><div style="margin-bottom:15px;"><strong>🛠️ Asignados:</strong><br>`;if(pa.length===0)ph+='<small style="color:var(--text-muted)">Nadie.</small>';pa.forEach(x=>{const a=App.state.artesanos.find(y=>y.id===x.artesano_id);const nt=(x.id.split('-').length>2)?x.id.split('-').slice(2).join(' '):'Trabajo';ph+=`<div style="display:flex;justify-content:space-between;background:#F7FAFC;padding:8px;margin-top:5px;border-radius:4px;font-size:0.85rem;border:1px solid #E2E8F0;"><span>🧑‍🎨 <strong>${a?a.nombre:'?'}</strong> - <em>${nt}</em></span><span><strong style="color:var(--success);margin-right:8px;">$${x.total}</strong> <span style="cursor:pointer;color:red;" onclick="App.ui.closeSheet(); App.logic.eliminarRegistroGenerico('pago_artesanos','${x.id}','pago_artesanos');">🗑️</span></span></div>`;});ph+=`</div><button type="button" class="btn btn-secondary" style="width:100%;margin-bottom:10px;border-style:dashed;" onclick="App.ui.closeSheet(); setTimeout(()=>App.views.formAgregarTrabajo('${oId}'),300);">+ Asignar Tarea</button><button type="button" class="btn btn-secondary" style="width:100%;margin-bottom:15px;border:1px solid var(--primary);color:var(--primary);background:transparent;" onclick="App.logic.imprimirTicketProduccion('${oId}')">🖨️ Ticket Taller</button>`;const form=`<form id="dynamic-form">${ph}<div class="form-group"><label>Estado Taller</label><select name="estado"><option value="pendiente" ${o.estado==='pendiente'?'selected':''}>Pendiente</option><option value="en_proceso" ${o.estado==='en_proceso'?'selected':''}>En Proceso</option><option value="listo" ${o.estado==='listo'?'selected':''}>¡Terminada!</option></select></div><button type="submit" class="btn btn-primary" style="width:100%;">Guardar</button></form>`;App.ui.openSheet(`Orden ${oId}`,form,(d)=>App.logic.procesarCambioOrden(oId,d));};
App.views.formMandarProduccion=function(pId){if(typeof pId!=='string')pId=null;const p=App.state.pedidos.find(x=>x.id===pId);const d=App.state.pedido_detalle.find(x=>x.pedido_id===pId);const pr=App.state.productos.find(x=>x.id===d.producto_id);let rh='';if(pr){let c=1;while(pr[`mat_${c}`]){const mId=pr[`mat_${c}`];const ct=parseFloat(pr[`cant_${c}`])*(parseInt(d.cantidad)||1);const u=pr[`uso_${c}`]||'Cuerpo';if(mId)rh+=window.generarFilaRecetaProd(mId,ct,u);c++;}}if(rh==='')rh=window.generarFilaRecetaProd('','','Cuerpo');const form=`<form id="dynamic-form"><input type="hidden" name="pedido_id" value="${pId}"><input type="hidden" name="pedido_detalle_id" value="${d.id}"><div style="background:#EBF8FF;padding:10px;border-radius:8px;margin-bottom:15px;font-size:0.85rem;color:#2B6CB0;"><strong>Confirmar Insumos</strong><br>Se descontará stock.</div><div id="cont-receta-prod">${rh}</div><button type="button" class="btn btn-secondary" style="width:100%;margin-top:10px;border:1px dashed var(--primary);color:var(--primary);background:transparent;" onclick="window.agregarFilaRecetaProd()">+ Añadir extra</button><button type="submit" class="btn btn-primary" style="width:100%;margin-top:15px;background:var(--success);border-color:var(--success);">Mandar a Taller</button></form>`;App.ui.openSheet("A Producción",form,(da)=>App.logic.confirmarMandarProduccion(da));};
App.views.formCerrarOrden=function(oId){if(typeof oId!=='string')oId=null;const o=App.state.ordenes_produccion.find(x=>x.id===oId);const d=App.state.pedido_detalle.find(x=>x.id===o.pedido_detalle_id)||App.state.pedido_detalle.find(x=>x.pedido_id===o.pedido_detalle_id)||{};const p=d.producto_id?App.state.productos.find(x=>x.id===d.producto_id):{nombre:'Hamaca',tubos_hilo:0};let mh='';let rg=null;try{if(o.receta_personalizada)rg=JSON.parse(o.receta_personalizada);}catch(e){}if(rg&&rg.length>0){rg.forEach((i,idx)=>{const m=App.state.inventario.find(x=>x.id===i.mat_id);if(m){mh+=`<div class="form-group" style="margin-bottom:8px;background:white;padding:8px;border-radius:4px;border:1px solid #e2e8f0;"><label>${m.nombre} <strong style="color:var(--primary);">[${(i.uso||'Cuerpo').toUpperCase()}]</strong></label><input type="hidden" name="mat_${idx+1}_id" value="${i.mat_id}"><input type="hidden" name="mat_${idx+1}_teorico" value="${i.cant}"><div style="display:flex;align-items:center;gap:10px;"><span style="font-size:0.8rem;">Consumo Real:</span><input type="number" step="0.1" name="mat_${idx+1}_real" value="${i.cant}" required style="flex:1;"></div></div>`;}});}else{for(let i=1;i<=20;i++){const mId=p[`mat_${i}`];const ct=parseFloat(p[`cant_${i}`]);const u=p[`uso_${i}`]||'Cuerpo';if(mId&&ct>0){const m=App.state.inventario.find(x=>x.id===mId);const cteo=ct*parseInt(d.cantidad||1);mh+=`<div class="form-group" style="margin-bottom:8px;background:white;padding:8px;border-radius:4px;border:1px solid #e2e8f0;"><label>${m?m.nombre:'Insumo'} <strong style="color:var(--primary);">[${u.toUpperCase()}]</strong></label><input type="hidden" name="mat_${i}_id" value="${mId}"><input type="hidden" name="mat_${i}_teorico" value="${cteo}"><div style="display:flex;align-items:center;gap:10px;"><span style="font-size:0.8rem;">Consumo Real:</span><input type="number" step="0.1" name="mat_${i}_real" value="${cteo}" required style="flex:1;"></div></div>`;}}}if(mh==='')mh='<p style="color:var(--text-muted);font-size:0.8rem;">No hay insumos a descontar.</p>';const form=`<div style="background:#EBF8FF;padding:10px;border-radius:8px;margin-bottom:15px;font-size:0.9rem;color:#2B6CB0;"><strong>Cierre Producción</strong><br>${p.nombre}</div><form id="dynamic-form"><input type="hidden" name="orden_id" value="${oId}"><p style="font-size:0.8rem;color:var(--text-muted);margin-bottom:10px;">Si hubo merma ajústalo aquí.</p>${mh}<div style="margin-top:15px;padding:10px;background:#E2E8F0;border-radius:6px;"><label style="display:flex;align-items:center;gap:8px;"><input type="checkbox" name="sumar_stock" value="1" style="width:20px;height:20px;"><strong>Guardar en Bodega</strong></label><small style="color:var(--text-muted);display:block;margin-top:5px;">Si NO se entrega hoy a cliente, marca para stock.</small></div><button type="submit" class="btn btn-primary" style="width:100%;margin-top:15px;background:var(--success);border-color:var(--success);">Finalizar Orden</button></form>`;App.ui.openSheet("Cerrar Orden",form,(d)=>App.logic.cerrarOrdenProduccion(d));};

App.views.clientes=function(){document.getElementById('bottom-nav').style.display='flex';let h=`<div class="card"><h3 class="card-title">Clientes</h3><button class="btn btn-secondary" style="width:100%;margin-bottom:15px;border-color:#38A169;color:#38A169;background:transparent;" onclick="window.exportarAExcel(App.state.clientes,'Clientes')">📥 Excel</button><input type="text" id="bus-cli" onkeyup="window.filtrarLista('bus-cli','tarj-cli')" placeholder="🔍 Buscar..." style="width:100%;padding:8px;margin-bottom:15px;border-radius:6px;border:1px solid var(--border);">`;App.state.clientes.forEach(c=>{h+=`<div class="card tarj-cli" style="border:1px solid var(--border);padding:10px;margin-bottom:8px;display:flex;justify-content:space-between;align-items:center;"><div><strong>${c.nombre}</strong><br><small style="color:var(--text-muted);">📞 ${c.telefono||'N/A'}</small></div><div><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;margin-right:4px;border-color:var(--primary);color:var(--primary);background:transparent;" onclick="App.views.modalEstadoCuenta('${c.id}')">📋 Perfil</button><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;margin-right:4px;" onclick="App.views.formCliente('${c.id}')">✏️</button><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;color:red;border-color:red;" onclick="App.logic.eliminarRegistroGenerico('clientes','${c.id}','clientes')">🗑️</button></div></div>`;});h+=`</div><button class="fab" onclick="App.views.formCliente()">+</button>`;return h;};
App.views.proveedores=function(){document.getElementById('bottom-nav').style.display='flex';let h=`<div class="card"><h3 class="card-title">Proveedores</h3>`;App.state.proveedores.forEach(p=>{h+=`<div class="card" style="border:1px solid var(--border);padding:10px;margin-bottom:8px;display:flex;justify-content:space-between;align-items:center;"><div><strong>${p.nombre}</strong><br><small style="color:var(--text-muted);">📞 ${p.telefono||'N/A'}</small></div><div><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;margin-right:4px;" onclick="App.views.formProveedor('${p.id}')">✏️</button><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;color:red;border-color:red;" onclick="App.logic.eliminarRegistroGenerico('proveedores','${p.id}','proveedores')">🗑️</button></div></div>`;});h+=`</div><button class="fab" onclick="App.views.formProveedor()">+</button>`;return h;};
App.views.artesanos=function(){document.getElementById('bottom-nav').style.display='flex';let h=`<div class="card"><h3 class="card-title">Artesanos</h3>`;App.state.artesanos.forEach(a=>{h+=`<div class="card" style="border:1px solid var(--border);padding:10px;margin-bottom:8px;display:flex;justify-content:space-between;align-items:center;"><div><strong>${a.nombre}</strong><br><small style="color:var(--text-muted);">📞 ${a.telefono||'N/A'}</small></div><div><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;margin-right:4px;border:1px solid var(--primary);color:var(--primary);background:transparent;" onclick="App.views.verTarifasArtesano('${a.id}')">Tarifas 💲</button><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;margin-right:4px;" onclick="App.views.formArtesano('${a.id}')">✏️</button><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;color:red;border-color:red;" onclick="App.logic.eliminarRegistroGenerico('artesanos','${a.id}','artesanos')">🗑️</button></div></div>`;});h+=`</div><button class="fab" onclick="App.views.formArtesano()">+</button>`;return h;};
App.views.productos=function(){document.getElementById('bottom-nav').style.display='flex';let h=`<div class="card"><h3 class="card-title">Productos</h3><input type="text" id="bus-prod" onkeyup="window.filtrarLista('bus-prod','tarj-prod')" placeholder="🔍 Buscar..." style="width:100%;padding:8px;margin-bottom:15px;border-radius:6px;border:1px solid var(--border);">`;if(!App.state.productos||App.state.productos.length===0){h+=`<p style="color:var(--text-muted);">Vacio.</p>`;}else{App.state.productos.forEach(p=>{h+=`<div class="card tarj-prod" style="border:1px solid var(--border);box-shadow:none;padding:12px;display:flex;justify-content:space-between;align-items:center;"><div style="flex:1;"><strong>${p.nombre}</strong><br><small style="color:var(--text-muted);">Cat: ${p.categoria||'Gral'} | Clasif: ${p.clasificacion||'Norm'}<br>Tam: ${p.tamano||'-'} | Col: ${p.color||'-'}</small></div><div style="text-align:right;"><span style="color:var(--primary);font-weight:bold;display:block;margin-bottom:5px;">$${p.precio_venta} <br><small style="color:var(--text-muted);">May: $${p.precio_mayoreo||'N/A'}</small></span><div><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;margin-right:4px;" onclick="App.views.formProducto('${p.id}')">✏️</button><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;color:red;border-color:red;" onclick="App.logic.eliminarRegistroGenerico('productos','${p.id}','productos')">🗑️</button></div></div></div>`;});}h+=`</div><button class="fab" onclick="App.views.formProducto()">+</button>`;return h;};
App.views.compras=function(){document.getElementById('bottom-nav').style.display='flex';let h=`<div class="card"><h3 class="card-title">Compras</h3>`;[...(App.state.compras||[])].reverse().forEach(c=>{const p=App.state.proveedores.find(x=>x.id===c.proveedor_id);h+=`<div class="card" style="border:1px solid var(--border);box-shadow:none;"><div style="display:flex;justify-content:space-between;margin-bottom:5px;cursor:pointer;" onclick="App.views.verDetallesCompra('${c.id}')"><strong>${c.id}</strong><span style="color:var(--danger);font-weight:bold;">$${c.total}</span></div><p style="color:var(--text-muted);font-size:0.85rem;margin-bottom:5px;cursor:pointer;" onclick="App.views.verDetallesCompra('${c.id}')">Prov: ${p?p.nombre:'Gral'} | Fecha: ${c.fecha}<br><span style="color:var(--primary);font-weight:bold;display:inline-block;margin-top:5px;">👀 Ver arts</span></p><div style="text-align:right;border-top:1px dashed #eee;padding-top:8px;margin-top:8px;"><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;margin-right:4px;" onclick="App.views.formEditarCompra('${c.id}')">✏️ Editar</button><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;color:red;border-color:red;" onclick="App.logic.eliminarCompra('${c.id}')">🗑️ Eliminar</button></div></div>`;});return h+=`</div><button class="fab" onclick="App.views.formCompra()">+</button>`;};
App.views.reparaciones=function(){document.getElementById('bottom-nav').style.display='flex';let h=`<div class="card"><h3 class="card-title">Reparaciones</h3>`;[...App.state.reparaciones].reverse().forEach(r=>{const c=App.state.clientes.find(x=>x.id===r.cliente_id);const pa=App.state.pago_artesanos.filter(p=>p.orden_id===r.id);let ia=pa.length>0?`🛠️ ${pa.length} Trabajos`:'👤 Sin asignar';const el=r.estado==='entregada';h+=`<div class="card" style="border:1px solid var(--border);box-shadow:none;"><div style="display:flex;justify-content:space-between;margin-bottom:8px;"><strong>${r.id} - ${c?c.nombre:'Cliente'}</strong><span class="badge ${el?'listo':'pendiente'}">${String(r.estado||'recibida').toUpperCase()}</span></div><p style="color:var(--primary);font-size:0.9rem;font-weight:bold;margin-bottom:5px;">${r.descripcion||'Reparación'}</p><div style="font-size:0.8rem;margin-bottom:5px;color:#4A5568;display:flex;justify-content:space-between;"><span>Cobro: <strong>$${r.precio||0}</strong></span><span>Pagado: <strong style="color:var(--success);">$${r.anticipo||0}</strong></span></div><div style="font-size:0.8rem;margin-bottom:10px;color:#4A5568;">${ia}</div><div style="display:flex;justify-content:space-between;gap:5px;margin-bottom:8px;">`;if(!el){h+=`<button class="btn btn-secondary" style="font-size:0.8rem;padding:6px;flex:1;" onclick="App.views.formAgregarTrabajo('${r.id}',true)">+ Tarea</button><button class="btn btn-primary" style="font-size:0.8rem;padding:6px;background:var(--success);border-color:var(--success);flex:1;" onclick="App.logic.actualizarReparacion('${r.id}','entregada')">✔ Lista</button>`;}h+=`</div><div style="display:flex;gap:5px;"><button class="btn btn-secondary" style="padding:6px;font-size:0.8rem;flex:1;" onclick="App.views.formNuevaReparacion('${r.id}')">✏️ Editar/Abono</button><button class="btn btn-secondary" style="padding:6px;font-size:0.8rem;color:red;" onclick="App.logic.eliminarReparacion('${r.id}')">🗑️</button></div></div>`;});return h+=`</div><button class="fab" onclick="App.views.formNuevaReparacion()">+</button>`;};
App.views.cotizaciones=function(){document.getElementById('bottom-nav').style.display='flex';let h=`<div class="card"><h3 class="card-title">Cotizaciones</h3><p style="color:var(--text-muted);font-size:0.85rem;margin-bottom:15px;">No afectan inventario ni finanzas.</p>`;if(!App.state.cotizaciones||App.state.cotizaciones.length===0){h+=`<p>Vacío.</p>`;}else{[...App.state.cotizaciones].reverse().forEach(c=>{h+=`<div class="card" style="border:1px solid var(--border);box-shadow:none;"><div style="display:flex;justify-content:space-between;margin-bottom:5px;"><strong>${c.id} - ${c.cliente_nombre}</strong><span style="color:var(--primary);font-weight:bold;">$${c.total}</span></div><p style="color:var(--text-muted);font-size:0.85rem;margin-bottom:5px;">${c.descripcion}</p><div style="display:flex;gap:5px;justify-content:flex-end;"><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;margin-right:4px;" onclick="App.logic.imprimirCotizacion('${c.id}')">🖨️ PDF</button><button class="btn btn-secondary" style="padding:4px 8px;font-size:0.8rem;color:red;border-color:red;" onclick="App.logic.eliminarCotizacion('${c.id}')">🗑️</button></div></div>`;});}h+=`</div><button class="fab" onclick="App.views.formNuevaCotizacion()">+</button>`;return h;};

App.views.formTarifa=function(aId,tId=null){if(typeof tId!=='string')tId=null;const o=tId?App.state.tarifas_artesano.find(x=>x.id===tId):null;const f=`<form id="dynamic-form"><input type="hidden" name="artesano_id" value="${aId}"><div class="form-group"><label>Tarea</label><input type="text" name="clasificacion" value="${o?o.clasificacion:''}" required placeholder="Nombre tarea"></div><div class="form-group"><label>Monto ($)</label><input type="number" step="0.01" name="monto" value="${o?o.monto:''}" required></div><button type="submit" class="btn btn-primary" style="width:100%;margin-top:10px;">${o?'Guardar Cambios':'Guardar'}</button></form>`;App.ui.openSheet(o?"Editar Tarea":"Nueva Tarea",f,(d)=>{if(o)App.logic.actualizarRegistroGenerico("tarifas_artesano",tId,d,"tarifas_artesano",()=>setTimeout(()=>App.views.verTarifasArtesano(aId),400));else App.logic.guardarNuevoGenerico("tarifas_artesano",d,"TAR","tarifas_artesano",()=>setTimeout(()=>App.views.verTarifasArtesano(aId),400));});};
App.views.formMaterial=function(id=null,cb=null){if(typeof id!=='string')id=null;const o=id?App.state.inventario.find(x=>x.id===id):null;const f=`<form id="dynamic-form"><div class="form-group"><label>Nombre</label><input type="text" name="nombre" value="${o?o.nombre:''}" required></div><div class="form-group"><label>Tipo</label><select name="tipo" required><option value="hilo" ${o&&o.tipo==='hilo'?'selected':''}>Hilo</option><option value="accesorio" ${o&&o.tipo==='accesorio'?'selected':''}>Accesorio</option><option value="reventa" ${o&&o.tipo==='reventa'?'selected':''}>Reventa</option><option value="otro" ${o&&o.tipo==='otro'?'selected':''}>Otro</option></select></div><div class="form-group"><label>Unidad</label><select name="unidad"><option value="Tubos" ${o&&o.unidad==='Tubos'?'selected':''}>Tubos</option><option value="Kg" ${o&&o.unidad==='Kg'?'selected':''}>Kg</option><option value="Pzas" ${o&&o.unidad==='Pzas'?'selected':''}>Pzas</option></select></div><div class="grid-2"><div class="form-group"><label>Stock</label><input type="number" step="0.1" name="stock_actual" value="${o?o.stock_actual:'0'}" required></div><div class="form-group"><label>Stock Mínimo</label><input type="number" step="0.1" name="stock_minimo" value="${o?(o.stock_minimo||'0'):'0'}" required></div></div><button type="submit" class="btn btn-primary" style="width:100%;">${o?'Guardar':'Crear'}</button></form>`;App.ui.openSheet(o?"Editar Insumo":"Nuevo",f,(d)=>{if(o)App.logic.actualizarRegistroGenerico("materiales",id,d,"inventario");else App.logic.guardarNuevoGenerico("materiales",d,"MAT","inventario",cb);});};
App.views.formProducto=function(id=null,cb=null){if(typeof id!=='string')id=null;const o=id?App.state.productos.find(x=>x.id===id):null;let rh='';let c=1;if(o){while(o[`mat_${c}`]){rh+=window.generarFilaRecetaProd(o[`mat_${c}`],o[`cant_${c}`],o[`uso_${c}`]);c++;}}if(rh==='')rh=window.generarFilaRecetaProd('','','Cuerpo');const cf=o?o.clasificacion:'';const f=`<form id="dynamic-form"><div class="form-group"><label>Nombre</label><input type="text" name="nombre" value="${o?o.nombre:''}" required></div><div class="grid-2"><div class="form-group"><label>Cat</label><select name="categoria"><option value="fabricacion" ${o&&o.categoria==='fabricacion'?'selected':''}>Fab</option><option value="reventa" ${o&&o.categoria==='reventa'?'selected':''}>Rev</option></select></div><div class="form-group"><label>Clasif</label><select name="clasificacion"><option value="Unicolor" ${cf==='Unicolor'?'selected':''}>Uni</option><option value="Combinada" ${cf==='Combinada'?'selected':''}>Comb</option><option value="Reventa" ${cf==='Reventa'?'selected':''}>Rev</option></select></div></div><div class="grid-2"><div class="form-group"><label>Tam</label><input type="text" name="tamano" value="${o?(o.tamano||''):''}"></div><div class="form-group"><label>Col</label><input type="text" name="color" value="${o?(o.color||''):''}"></div></div><div class="grid-2"><div class="form-group"><label>Precio</label><input type="number" name="precio_venta" value="${o?o.precio_venta:''}" required></div><div class="form-group"><label>Mayoreo</label><input type="number" name="precio_mayoreo" value="${o?(o.precio_mayoreo||''):''}"></div></div><div style="background:#F7FAFC;padding:10px;border-radius:8px;margin-bottom:15px;border:1px solid var(--border);"><strong>📦 Receta (Dinámica)</strong><div id="cont-receta" style="margin-top:10px;">${rh}</div><button type="button" class="btn btn-secondary" style="width:100%;margin-top:10px;border:1px dashed var(--primary);color:var(--primary);background:transparent;" onclick="window.agregarFilaReceta()">+ Insumo</button></div><button type="submit" class="btn btn-primary" style="width:100%;">${o?'Guardar':'Crear'}</button></form>`;App.ui.openSheet(o?"Editar Producto":"Nuevo Producto",f,(d)=>{if(d.mat_id&&Array.isArray(d.mat_id)){for(let i=0;i<d.mat_id.length;i++){d[`mat_${i+1}`]=d.mat_id[i];d[`cant_${i+1}`]=d.cant[i];d[`uso_${i+1}`]=d.uso[i];}delete d.mat_id;delete d.cant;delete d.uso;}else if(d.mat_id){d.mat_1=d.mat_id;d.cant_1=d.cant;d.uso_1=d.uso;delete d.mat_id;delete d.cant;delete d.uso;}if(o)App.logic.actualizarRegistroGenerico("productos",id,d,"productos");else App.logic.guardarNuevoGenerico("productos",d,"PROD","productos",cb);});};
App.views.formCliente=function(id=null,cb=null){if(typeof id!=='string')id=null;const o=id?App.state.clientes.find(x=>x.id===id):null;const f=`<form id="dynamic-form"><div class="form-group"><label>Nombre</label><input type="text" name="nombre" value="${o?o.nombre:''}" required></div><div class="form-group"><label>Tel (10 d)</label><input type="tel" name="telefono" value="${o?o.telefono:''}" pattern="\\d{10}" maxlength="10"></div><div class="form-group"><label>Direc</label><input type="text" name="direccion" value="${o?o.direccion:''}"></div><button type="submit" class="btn btn-primary" style="width:100%;">${o?'Guardar':'Crear'}</button></form>`;App.ui.openSheet(o?"Editar":"Nuevo",f,(d)=>{if(o)App.logic.actualizarRegistroGenerico("clientes",id,d,"clientes");else App.logic.guardarNuevoGenerico("clientes",d,"CLI","clientes",cb);});};
App.views.formProveedor=function(id=null,cb=null){if(typeof id!=='string')id=null;const o=id?App.state.proveedores.find(x=>x.id===id):null;const f=`<form id="dynamic-form"><div class="form-group"><label>Nombre</label><input type="text" name="nombre" value="${o?o.nombre:''}" required></div><div class="form-group"><label>Tel (10 d)</label><input type="tel" name="telefono" value="${o?o.telefono:''}" pattern="\\d{10}" maxlength="10"></div><button type="submit" class="btn btn-primary" style="width:100%;">${o?'Guardar':'Crear'}</button></form>`;App.ui.openSheet(o?"Editar":"Nuevo",f,(d)=>{if(o)App.logic.actualizarRegistroGenerico("proveedores",id,d,"proveedores");else App.logic.guardarNuevoGenerico("proveedores",d,"PRV","proveedores",cb);});};
App.views.formArtesano=function(id=null){if(typeof id!=='string')id=null;const o=id?App.state.artesanos.find(x=>x.id===id):null;const f=`<form id="dynamic-form"><div class="form-group"><label>Nombre</label><input type="text" name="nombre" value="${o?o.nombre:''}" required></div><div class="form-group"><label>Tel</label><input type="tel" name="telefono" value="${o?o.telefono:''}" pattern="\\d{10}" maxlength="10"></div><button type="submit" class="btn btn-primary" style="width:100%;">${o?'Guardar':'Crear'}</button></form>`;App.ui.openSheet(o?"Editar":"Nuevo",f,(d)=>{if(o)App.logic.actualizarRegistroGenerico("artesanos",id,d,"artesanos");else App.logic.guardarNuevoGenerico("artesanos",d,"ART","artesanos");});};
App.views.formEditarPedido=function(id){if(typeof id!=='string')id=null;const p=App.state.pedidos.find(x=>x.id===id);const fc=p.fecha_creacion?p.fecha_creacion.split('T')[0]:'';const f=`<form id="dynamic-form"><div class="form-group"><label>Fecha</label><input type="date" name="fecha_creacion" value="${fc}" required></div><div class="form-group"><label>Total ($)</label><input type="number" step="0.01" name="total" value="${p.total}" required></div><div class="form-group"><label>Anticipo ($)</label><input type="number" step="0.01" name="anticipo" value="${p.anticipo}" required></div><div class="form-group"><label>Entrega</label><input type="date" name="fecha_entrega" value="${p.fecha_entrega||''}"></div><div class="form-group"><label>Notas</label><textarea name="notas" rows="2">${p.notas||''}</textarea></div><button type="submit" class="btn btn-primary" style="width:100%;">Guardar</button></form>`;App.ui.openSheet("Editar",f,(d)=>{if(d.fecha_creacion)d.fecha_creacion+="T12:00:00.000Z";App.logic.actualizarRegistroGenerico("pedidos",id,d,"pedidos");});};
App.views.formGasto=function(id=null){if(typeof id!=='string')id=null;const o=id?App.state.gastos.find(x=>x.id===id):null;let hg='';if(o){hg=`<div class="form-group"><label>Desc</label><input type="text" name="descripcion" value="${o.descripcion}" required></div><div class="form-group"><label>Monto</label><input type="number" step="0.01" name="monto" value="${o.monto}" required></div>`;}else{hg=`<div id="cont-gastos"><div class="grid-2 fila-dinamica" style="margin-bottom:5px;"><div class="form-group" style="margin:0;"><input type="text" name="descripcion[]" placeholder="Desc" required></div><div class="form-group" style="margin:0;display:flex;gap:5px;"><input type="number" step="0.01" name="monto[]" placeholder="$" required></div></div></div><button type="button" class="btn btn-secondary" style="width:100%;margin-top:10px;margin-bottom:15px;border:1px dashed var(--danger);color:var(--danger);background:transparent;" onclick="window.agregarFilaGasto()">+ Añadir</button>`;}const f=`<form id="dynamic-form"><div class="form-group"><label>Cat</label><select name="categoria" required><option value="materiales" ${o&&o.categoria==='materiales'?'selected':''}>Mat</option><option value="servicios" ${o&&o.categoria==='servicios'?'selected':''}>Serv</option><option value="nomina" ${o&&o.categoria==='nomina'?'selected':''}>Nom</option><option value="otro" ${o&&o.categoria==='otro'?'selected':''}>Otro</option></select></div><div class="form-group"><label>Fecha</label><input type="date" name="fecha" value="${o?o.fecha:new Date().toISOString().split('T')[0]}" required></div>${hg}<button type="submit" class="btn btn-primary" style="width:100%;background:var(--danger);border-color:var(--danger);">${o?'Guardar':'Registrar'}</button></form>`;App.ui.openSheet(o?"Editar Gasto":"Gastos Múltiples",f,(d)=>{if(o)App.logic.actualizarRegistroGenerico("gastos",id,d,"gastos");else App.logic.guardarMultiplesGastos(d);});};
App.views.formNuevoPedido=function(){const oc=App.state.clientes.map(c=>`<option value="${c.id}">${c.nombre}</option>`).join('');const op=App.state.productos.map(p=>`<option value="${p.id}">${p.nombre}</option>`).join('');const hy=new Date().toISOString().split('T')[0];const f=`<form id="dynamic-form"><div class="form-group"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px;"><label style="margin:0;">Cliente</label><span style="color:var(--primary);font-size:0.8rem;cursor:pointer;font-weight:bold;" onclick="App.ui.closeSheet();setTimeout(()=>App.views.formCliente(null,()=>App.views.formNuevoPedido()),400);">+ Nuevo</span></div><select name="cliente_id" required><option value="">-- Elige --</option>${oc}</select></div><div class="form-group"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px;"><label style="margin:0;">Producto</label><span style="color:var(--primary);font-size:0.8rem;cursor:pointer;font-weight:bold;" onclick="App.ui.closeSheet();setTimeout(()=>App.views.formProducto(null,()=>App.views.formNuevoPedido()),400);">+ Nuevo</span></div><select name="producto_id" required onchange="window.calcularTotalPedido()"><option value="">-- Elige --</option>${op}</select></div><div id="info-extra-prod" style="margin-top:-10px;margin-bottom:10px;"></div><div class="form-group"><label style="display:flex;align-items:center;gap:8px;"><input type="checkbox" name="es_mayoreo" value="1" onchange="window.calcularTotalPedido()" style="width:20px;height:20px;"><strong>Mayoreo</strong></label></div><div class="grid-2"><div class="form-group"><label>Fecha</label><input type="date" name="fecha_creacion" value="${hy}" required></div><div class="form-group"><label>Entrega</label><input type="date" name="fecha_entrega" required></div></div><div class="grid-2"><div class="form-group"><label>Cant</label><input type="number" name="cantidad" value="1" min="1" required oninput="window.calcularTotalPedido()"></div><div class="form-group"><label>Total ($)</label><input type="number" name="total" required></div></div><div class="form-group"><label>Anticipo ($)</label><input type="number" name="anticipo" value="0" required></div><div class="form-group"><label>Notas</label><input type="text" name="notas"></div><button type="submit" class="btn btn-primary" style="width:100%;margin-top:10px;">Crear</button></form>`;App.ui.openSheet("Nuevo Pedido",f,(d)=>App.logic.guardarNuevoPedido(d));};
App.views.formOrdenStock=function(){const op=App.state.productos.map(p=>`<option value="${p.id}">${p.nombre}</option>`).join('');const f=`<form id="dynamic-form"><div class="form-group"><select name="producto_id" required><option value="">-- Elige --</option>${op}</select></div><div class="form-group"><label>Cantidad</label><input type="number" name="cantidad" value="1" min="1" required></div><button type="submit" class="btn btn-primary" style="width:100%;margin-top:10px;">Mandar a Producción</button></form>`;App.ui.openSheet("Para Stock",f,(d)=>App.logic.guardarOrdenStock(d));};
