App.views.formAgregarTrabajo=function(oId,e=false){const oa=App.state.artesanos.map(a=>`<option value="${a.id}">${a.nombre}</option>`).join('');const f=`<form id="dynamic-form"><div class="form-group"><label>Artesano</label><select name="artesano_id" required onchange="window.cargarTarifas(this.value)"><option value="">-- Sel --</option>${oa}</select></div><div class="form-group"><label>Tarea</label><select name="tarea_val" id="select-tarifas" required onchange="window.calcTotalTrabajo()"><option value="">-- Elige artesano --</option></select></div><input type="hidden" name="tarea_nombre" id="tarea_nombre"><div class="form-group"><label>Cant</label><input type="number" step="0.1" name="cantidad" id="cant-trabajo" value="1" required oninput="window.calcTotalTrabajo()"></div><div class="form-group"><label>Total ($)</label><input type="number" step="0.01" name="total" id="total-trabajo" required readonly style="background:#f0f0f0;"></div><button type="submit" class="btn btn-primary" style="width:100%;margin-top:10px;">Guardar</button></form>`;App.ui.openSheet("Añadir Tarea",f,(d)=>App.logic.guardarTrabajoOrden(oId,d,e));};
App.views.formCompra=function(){const opv=App.state.proveedores.map(p=>`<option value="${p.id}">${p.nombre}</option>`).join('');const om=App.state.inventario.map(m=>`<option value="${m.id}">${m.nombre} (S:${m.stock_actual})</option>`).join('');const f=`<form id="dynamic-form"><div class="form-group"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px;"><label style="margin:0;">Prov</label><span style="color:var(--primary);font-size:0.8rem;cursor:pointer;font-weight:bold;" onclick="App.ui.closeSheet();setTimeout(()=>App.views.formProveedor(null,()=>App.views.formCompra()),400);">+ Nuevo</span></div><select name="proveedor_id" required><option value="">-- Elige --</option>${opv}</select></div><div style="background:#EBF8FF;padding:10px;border-radius:8px;margin-bottom:15px;"><div id="cont-compras"><div class="fila-compra" style="background:white;padding:10px;border-radius:6px;border:1px solid #e2e8f0;margin-bottom:10px;"><div style="margin-bottom:5px;"><select name="mat_id[]" required style="width:100%;"><option value="">-- Insumo --</option>${om}</select></div><div style="display:flex;gap:5px;align-items:center;"><input type="number" step="0.1" name="cant[]" placeholder="C" required oninput="window.calcTotalCompra()" style="flex:1;padding:6px;"><input type="number" step="0.01" name="precio_u[]" placeholder="$U" required oninput="window.calcTotalCompra()" style="flex:1;padding:6px;"><input type="number" step="0.01" name="total_fila[]" placeholder="$T" readonly style="flex:1;padding:6px;background:#edf2f7;"></div></div></div><button type="button" class="btn btn-secondary" style="width:100%;margin-top:10px;border:1px dashed #3182CE;color:#3182CE;background:transparent;" onclick="window.agregarFilaCompra()">+ Añadir artículo</button></div><div class="form-group"><label>Fecha</label><input type="date" name="fecha" value="${new Date().toISOString().split('T')[0]}" required></div><div class="form-group"><label>Total ($)</label><input type="number" step="0.01" name="total" required readonly style="background:#f0f0f0;font-weight:bold;"></div><button type="submit" class="btn btn-primary" style="width:100%;margin-top:10px;background:var(--success);border-color:var(--success);">Comprar</button></form>`;App.ui.openSheet("Compra",f,(d)=>App.logic.guardarNuevaCompra(d));};
App.views.formEditarCompra=function(id){if(typeof id!=='string')id=null;const o=App.state.compras.find(c=>c.id===id);const op=App.state.proveedores.map(p=>`<option value="${p.id}" ${o.proveedor_id===p.id?'selected':''}>${p.nombre}</option>`).join('');const f=`<form id="dynamic-form"><div class="form-group"><label>Prov</label><select name="proveedor_id" required>${op}</select></div><div class="form-group"><label>Fecha</label><input type="date" name="fecha" value="${o.fecha}" required></div><div class="form-group"><label>Total Pagado ($)</label><input type="number" name="total" value="${o.total}" required></div><button type="submit" class="btn btn-primary" style="width:100%;margin-top:10px;">Guardar</button></form>`;App.ui.openSheet("Editar Compra",f,(d)=>App.logic.actualizarRegistroGenerico("compras",id,d,"compras"));};
App.views.formNuevaReparacion=function(id=null){if(typeof id!=='string')id=null;const o=id?App.state.reparaciones.find(x=>x.id===id):null;const oc=App.state.clientes.map(c=>`<option value="${c.id}" ${o&&o.cliente_id===c.id?'selected':''}>${c.nombre}</option>`).join('');const f=`<form id="dynamic-form"><div class="form-group"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px;"><label style="margin:0;">Cliente</label><span style="color:var(--primary);font-size:0.8rem;cursor:pointer;font-weight:bold;" onclick="App.ui.closeSheet();setTimeout(()=>App.views.formCliente(null,()=>App.views.formNuevaReparacion('${id||''}')),400);">+ Nuevo</span></div><select name="cliente_id" required><option value="">-- Elige --</option>${oc}</select></div><div class="form-group"><label>Desc</label><input type="text" name="descripcion" value="${o?o.descripcion:''}" required></div><div class="form-group"><label>Costo Total ($)</label><input type="number" step="0.01" name="precio" value="${o?o.precio:''}" required></div><div class="form-group"><label>Pagado/Anticipo ($)</label><input type="number" step="0.01" name="anticipo" value="${o?o.anticipo:'0'}" required></div>${o?`<div class="form-group"><label>Estado</label><select name="estado"><option value="recibida" ${o.estado==='recibida'?'selected':''}>Pend</option><option value="entregada" ${o.estado==='entregada'?'selected':''}>Lista</option></select></div>`:''}<button type="submit" class="btn btn-primary" style="width:100%;margin-top:10px;">${o?'Guardar':'Registrar'}</button></form>`;App.ui.openSheet(o?"Editar Reparación":"Nueva Reparación",f,(d)=>{if(o)App.logic.actualizarRegistroGenerico("reparaciones",id,d,"reparaciones");else App.logic.guardarNuevaReparacion(d);});};
App.views.formNuevaCotizacion=function(){const f=`<form id="dynamic-form"><div class="form-group"><label>Cliente</label><input type="text" name="cliente_nombre" required></div><div class="form-group"><label>Desc</label><input type="text" name="descripcion" required></div><div class="form-group"><label>Precio ($)</label><input type="number" step="0.01" name="total" required></div><button type="submit" class="btn btn-primary" style="width:100%;">Generar</button></form>`;App.ui.openSheet("Cotización",f,(d)=>App.logic.guardarCotizacion(d));};

App.router.init=function(){window.addEventListener('hashchange',()=>this.handleRoute());this.handleRoute();};
App.router.navigate=function(r){window.location.hash=r;};
App.router.handleRoute=function(){if(!App.state.pinAcceso){App.ui.hideLoader();document.getElementById('app-content').innerHTML=App.views.login();document.getElementById('header-title').textContent="Acceso Restringido";return;}let h=window.location.hash.substring(1)||'inicio';const c=document.getElementById('app-content');const t=document.getElementById('header-title');document.querySelectorAll('.nav-item').forEach(x=>x.classList.remove('active'));const a=document.querySelector(`.nav-item[data-view="${h}"]`);if(a)a.classList.add('active');if(App.views[h]){c.innerHTML=App.views[h]();t.textContent=h.charAt(0).toUpperCase()+h.slice(1);}else{c.innerHTML=`<div class="card"><p style="text-align:center;padding:20px;">Módulo no encontrado.</p></div>`;}};

App.start=function(){this.ui.init();if(!this.state.pinAcceso)this.router.init();else this.logic.cargarDatosIniciales();};
document.addEventListener('DOMContentLoaded',()=>App.start());
